(window.webpackJsonp=window.webpackJsonp||[]).push([[206],{833:function(n,o){n.exports="\x3c!-- \ntitle: 13-微服务\nsort: \n--\x3e \n\n## Go-zero\n\n### 开始\n\n```bash\n# 生成api文件\ngoctl api -o xxx.api\n# 生成 API Gateway 代码\ngoctl api go -api xxx.api -dir .\n# 启动 API Gateway 服务\ngo run xxx.go -f etc/xxx-api.yaml\n\n# 生成 proto 文件模板\ngoctl rpc template -o transform.proto\n# 生成 rpc 代码\ngoctl rpc proto -src transform.proto -dir .\n# 运行\ngo run transform.go -f etc/transform.yaml\n# 查看服务是否注册在etcd\netcdctl get transform.rpc --prefix\n\n# 编写数据库创建sql文件\n# 生成代码\ngoctl model mysql ddl -c -src xxx.sql -dir .\n```\n\n"}}]);